function main() {
  if (!items.length) {
    return [];
  }

  // After XML node: XML string in `data` is now JSON
  const root = items[0].json;

  // Be defensive about where `feed` lives
  const feed =
    root.feed ||
    root.data?.feed ||
    root.data ||
    root;

  if (!feed || !feed.entry) {
    return [];
  }

  const entriesRaw = feed.entry;
  const entries = Array.isArray(entriesRaw) ? entriesRaw : [entriesRaw];

  const getText = (obj, key) => {
    if (!obj || obj[key] === undefined) return '';
    const v = obj[key];

    if (typeof v === 'string') return v;

    if (Array.isArray(v)) {
      const first = v[0];
      if (typeof first === 'string') return first;
      if (first && typeof first === 'object') return first._ || '';
      return '';
    }

    if (typeof v === 'object' && v !== null) {
      return v._ || '';
    }

    return '';
  };

  const newItems = entries.map((entry) => {
    const title = getText(entry, 'title').replace(/\s+/g, ' ').trim();
    const summary = getText(entry, 'summary').replace(/\s+/g, ' ').trim();
    const id = getText(entry, 'id');

    // Links
    let url = '';
    const linksRaw = entry.link || [];
    const links = Array.isArray(linksRaw) ? linksRaw : [linksRaw];

    if (links.length > 0) {
      const htmlLink = links.find((l) => {
        const attrs = l.$ || {};
        const rel = attrs.rel;
        const type = attrs.type;

        const relOk = !rel || rel === 'alternate';
        const typeOk = !type || String(type).includes('text/html');

        return relOk && typeOk;
      });

      const first = links[0];
      url = htmlLink?.$?.href || first?.$?.href || id;
    } else {
      url = id;
    }

    // Dates
    const publishedRaw =
      getText(entry, 'published') || getText(entry, 'updated');
    const publishedAt = publishedRaw || null;

    // Tags from category + primary_category
    const tags = [];

    if (entry.category) {
      const cats = Array.isArray(entry.category)
        ? entry.category
        : [entry.category];

      for (const c of cats) {
        const term = c.$?.term || getText(c, 'term');
        if (term && !tags.includes(term)) tags.push(term);
      }
    }

    if (entry['arxiv:primary_category']) {
      const prims = Array.isArray(entry['arxiv:primary_category'])
        ? entry['arxiv:primary_category']
        : [entry['arxiv:primary_category']];

      for (const c of prims) {
        const term = c.$?.term;
        if (term && !tags.includes(term)) tags.push(term);
      }
    }

    // Authors
    const authors = [];
    if (entry.author) {
      const auths = Array.isArray(entry.author)
        ? entry.author
        : [entry.author];

      for (const a of auths) {
        let name = '';
        if (a.name) {
          const v = a.name;
          if (typeof v === 'string') {
            name = v;
          } else if (Array.isArray(v)) {
            const first = v[0];
            if (typeof first === 'string') name = first;
            else if (first && typeof first === 'object') name = first._ || '';
          } else if (typeof v === 'object') {
            name = v._ || '';
          }
        }
        name = (name || '').trim();
        if (name) authors.push(name);
      }
    }

    return {
      json: {
        id: id || url,
        title,
        url,
        summary,
        publishedAt,
        source: 'arXiv',
        tags,
        authors,
        // Optional: if your downstream expects a channel
        // channel: 'ai_research_papers',
      },
    };
  });

  return newItems;
}

return main();
